def solve(s: str) -> str:
    result = []
    for c in s:
        if c.islower():
            result.append(c)
        elif c == '*':
            if result:
                result.pop()
        elif c == '#':
            result.extend(result)
        elif c == '%':
            result.reverse()
    return ''.join(result)
